args.sparql:
SELECT ?ownerLabel WHERE {
  ?player wdt:P569 ?birthDate ;
          wdt:P54 wd:Q130521 . # Guangzhou F.C.
  ?player wdt:P54 ?previousClub .
  ?previousClub wdt:P127 ?owner .
  ?owner rdfs:label ?ownerLabel .
  FILTER(YEAR(?birthDate) = 1983 && MONTH(?birthDate) = 6 && DAY(?birthDate) = 12) .
  FILTER(?previousClub != wd:Q130521) .
  FILTER(LANG(?ownerLabel) = "en") .
}

SELECT ?ownerLabel WHERE {
  ?player wdt:P569 "1983-06-12T00:00:00Z"^^xsd:dateTime ;
          wdt:P106 wd:Q937976 ;
          wdt:P54 ?previousClub .
  ?previousClub wdt:P127 ?owner .
  ?owner rdfs:label ?ownerLabel .
  FILTER (?previousClub != wd:Q130521) .
  FILTER (LANG(?ownerLabel) = "en") .
}
